NexaEvidenceDatabase = {}
local function coreDatabase() if GetResourceState('nexa-core') ~= 'started' then return nil end; local ok, core = pcall(function() return exports['nexa-core']:GetCoreObject() end); return ok and core and core.Database or nil end
local function encode(value) local ok, encoded = pcall(json.encode, value or {}); return ok and encoded or '{}' end
local function dbCall(method, sql, params, category) local db = coreDatabase(); if not db or not db[method] then return nil, { code = NEXA_EVIDENCE_ERRORS.databaseError } end; return db[method](sql, params or {}, { category = category or 'evidence.db' }) end
function NexaEvidenceDatabase.Migrate() local db = coreDatabase(); if not db or not db.RegisterMigration then return false end; db.RegisterMigration({ id = '164_evidence_foundation', description = 'Create evidence records traces locker and chain custody.', transaction = false, up = function() db.Query([[CREATE TABLE IF NOT EXISTS nexa_evidence_types (id INT AUTO_INCREMENT PRIMARY KEY, evidence_type VARCHAR(64) UNIQUE NOT NULL, label VARCHAR(128) NOT NULL, enabled TINYINT(1) NOT NULL DEFAULT 1, metadata LONGTEXT NULL)]], {}, { category = 'evidence.migration.types' }); db.Query([[CREATE TABLE IF NOT EXISTS nexa_evidence_records (id INT AUTO_INCREMENT PRIMARY KEY, evidence_type VARCHAR(32) NOT NULL, status VARCHAR(32) NOT NULL, collected_by BIGINT NULL, location_json LONGTEXT NULL, reference_json LONGTEXT NULL, package_key VARCHAR(128) NULL, case_reference VARCHAR(128) NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, metadata LONGTEXT NULL)]], {}, { category = 'evidence.migration.records' }); db.Query([[CREATE TABLE IF NOT EXISTS nexa_evidence_traces (id INT AUTO_INCREMENT PRIMARY KEY, trace_type VARCHAR(32) NOT NULL, source_reference VARCHAR(128) NULL, evidence_id INT NULL, expires_at TIMESTAMP NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, metadata LONGTEXT NULL)]], {}, { category = 'evidence.migration.traces' }); db.Query([[CREATE TABLE IF NOT EXISTS nexa_evidence_custody (id INT AUTO_INCREMENT PRIMARY KEY, evidence_id INT NOT NULL, action VARCHAR(64) NOT NULL, actor_character_id BIGINT NULL, from_location VARCHAR(128) NULL, to_location VARCHAR(128) NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, metadata LONGTEXT NULL)]], {}, { category = 'evidence.migration.custody' }); db.Query([[CREATE TABLE IF NOT EXISTS nexa_evidence_analysis (id INT AUTO_INCREMENT PRIMARY KEY, evidence_id INT NOT NULL, analysis_type VARCHAR(64) NOT NULL, status VARCHAR(32) NOT NULL, requested_by BIGINT NULL, completed_by BIGINT NULL, result_json LONGTEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, completed_at TIMESTAMP NULL, metadata LONGTEXT NULL)]], {}, { category = 'evidence.migration.analysis' }); db.Query([[CREATE TABLE IF NOT EXISTS nexa_evidence_locker (id INT AUTO_INCREMENT PRIMARY KEY, evidence_id INT NOT NULL, locker_key VARCHAR(64) NOT NULL, stored_by BIGINT NULL, stored_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, metadata LONGTEXT NULL)]], {}, { category = 'evidence.migration.locker' }); db.Query([[ALTER TABLE nexa_evidence_records ADD COLUMN IF NOT EXISTS package_key VARCHAR(128) NULL]], {}, { category = 'evidence.migration.records.package' }); db.Query([[ALTER TABLE nexa_evidence_records ADD COLUMN IF NOT EXISTS case_reference VARCHAR(128) NULL]], {}, { category = 'evidence.migration.records.case' }); db.Query([[ALTER TABLE nexa_evidence_records ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP]], {}, { category = 'evidence.migration.records.updated' }); db.Query([[ALTER TABLE nexa_evidence_traces ADD COLUMN IF NOT EXISTS expires_at TIMESTAMP NULL]], {}, { category = 'evidence.migration.traces.expires' }); db.Query([[CREATE INDEX IF NOT EXISTS idx_nexa_evidence_status ON nexa_evidence_records (status, evidence_type)]], {}, { category = 'evidence.migration.index.status' }); return true end }); return db.RunMigrations() end
function NexaEvidenceDatabase.UpsertType(t) return dbCall('Insert', 'INSERT INTO nexa_evidence_types (evidence_type, label, enabled, metadata) VALUES (?, ?, ?, ?) ON DUPLICATE KEY UPDATE label = VALUES(label), enabled = VALUES(enabled), metadata = VALUES(metadata)', { t.evidence_type, t.label, t.enabled and 1 or 0, encode(t.metadata) }, 'evidence.type.upsert') end
function NexaEvidenceDatabase.InsertEvidence(e) return dbCall('Insert', 'INSERT INTO nexa_evidence_records (evidence_type, status, collected_by, location_json, reference_json, metadata) VALUES (?, ?, ?, ?, ?, ?)', { e.evidence_type, e.status, e.collected_by, encode(e.location), encode(e.reference), encode(e.metadata) }, 'evidence.record.insert') end
function NexaEvidenceDatabase.GetEvidence(id) return dbCall('Single', 'SELECT * FROM nexa_evidence_records WHERE id = ? LIMIT 1', { id }, 'evidence.record.get') end
function NexaEvidenceDatabase.ListEvidence(filters) filters = type(filters) == 'table' and filters or {}; return dbCall('Query', 'SELECT * FROM nexa_evidence_records ORDER BY id DESC LIMIT ?', { tonumber(filters.limit) or 100 }, 'evidence.record.list') end
function NexaEvidenceDatabase.UpdateStatus(id, status) return dbCall('Update', 'UPDATE nexa_evidence_records SET status = ? WHERE id = ?', { status, id }, 'evidence.record.status') end
function NexaEvidenceDatabase.PackageEvidence(id, packageKey, caseReference) return dbCall('Update', 'UPDATE nexa_evidence_records SET status = ?, package_key = ?, case_reference = ? WHERE id = ? AND status IN (?, ?)', { NEXA_EVIDENCE_STATUS.packaged, packageKey, caseReference, id, NEXA_EVIDENCE_STATUS.collected, NEXA_EVIDENCE_STATUS.discovered }, 'evidence.record.package') end
function NexaEvidenceDatabase.InsertTrace(t) return dbCall('Insert', 'INSERT INTO nexa_evidence_traces (trace_type, source_reference, evidence_id, metadata) VALUES (?, ?, ?, ?)', { t.trace_type, t.source_reference, t.evidence_id, encode(t.metadata) }, 'evidence.trace.insert') end
function NexaEvidenceDatabase.StoreLocker(l) return dbCall('Insert', 'INSERT INTO nexa_evidence_locker (evidence_id, locker_key, stored_by, metadata) VALUES (?, ?, ?, ?)', { l.evidence_id, l.locker_key, l.stored_by, encode(l.metadata) }, 'evidence.locker.store') end
function NexaEvidenceDatabase.InsertCustody(c) return dbCall('Insert', 'INSERT INTO nexa_evidence_custody (evidence_id, action, actor_character_id, from_location, to_location, metadata) VALUES (?, ?, ?, ?, ?, ?)', { c.evidence_id, c.action, c.actor_character_id, c.from_location, c.to_location, encode(c.metadata) }, 'evidence.custody.insert') end
function NexaEvidenceDatabase.InsertAnalysis(a) return dbCall('Insert', 'INSERT INTO nexa_evidence_analysis (evidence_id, analysis_type, status, requested_by, result_json, metadata) VALUES (?, ?, ?, ?, ?, ?)', { a.evidence_id, a.analysis_type, a.status, a.requested_by, encode(a.result), encode(a.metadata) }, 'evidence.analysis.insert') end
function NexaEvidenceDatabase.CompleteAnalysis(id, actor, result) return dbCall('Update', 'UPDATE nexa_evidence_analysis SET status = ?, completed_by = ?, result_json = ?, completed_at = CURRENT_TIMESTAMP WHERE id = ? AND status = ?', { 'completed', actor, encode(result), id, 'pending' }, 'evidence.analysis.complete') end
function NexaEvidenceDatabase.GetSchema() return { migration = '164_evidence_foundation', tables = { 'nexa_evidence_types', 'nexa_evidence_records', 'nexa_evidence_traces', 'nexa_evidence_custody', 'nexa_evidence_analysis', 'nexa_evidence_locker' } } end
